 65→    // MARK: - TrainerStudentRepository
 66→
 67→    func requestConnection(
 68→        trainerId: String,
 69→        studentId: String,
 70→        studentDisplayName: String
 71→    ) async throws -> String {
 72→        guard let cmsService else {
 73→            throw DomainError.repositoryFailure(reason: "CMS service not available")
 74→        }
 75→
 76→        do {
 77→            let request = CMSConnectionRequest(
 78→                studentId: studentId,
 79→                studentName: studentDisplayName
 80→            )
 81→            let response = try await cmsService.requestConnection(
 82→                trainerId: trainerId,
 83→                connection: request
 84→            )
 85→            return response.id
 86→        } catch let error as CMSServiceError {
 87→            switch error {
 88→            case .unexpectedStatus(409):
 89→                throw DomainError.invalidInput(reason: "Connection already exists with this trainer")
 90→            default:
 91→                throw DomainError.repositoryFailure(reason: error.localizedDescription)
 92→            }
 93→        } catch {
 94→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
 95→        }
 96→    }
 97→
 98→    func cancelConnection(relationshipId: String) async throws {
 99→        do {
100→            try await service.cancelConnection(relationshipId: relationshipId)
101→        } catch {
102→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
103→        }
104→    }
