106→    func getCurrentRelationship(studentId: String) async throws -> TrainerStudentRelationship? {
107→        do {
108→            guard let result = try await service.getCurrentRelationship(studentId: studentId) else {
109→                return nil
110→            }
111→            return PersonalTrainerMapper.toRelationship(result.1, id: result.0)
112→        } catch {
113→            throw DomainError.repositoryFailure(reason: error.localizedDescription)
