142→    var streakDays: Int {
143→        guard !historyEntries.isEmpty else { return 0 }
144→
145→        let calendar = Calendar.current
146→        let sortedDates = historyEntries
147→            .map { calendar.startOfDay(for: $0.date) }
148→            .sorted(by: >)
149→
150→        guard let mostRecent = sortedDates.first else { return 0 }
151→
152→        // Check if streak is still active (workout today or yesterday)
153→        let today = calendar.startOfDay(for: Date())
154→        let yesterday = calendar.date(byAdding: .day, value: -1, to: today)!
155→
156→        guard mostRecent >= yesterday else { return 0 }
157→
158→        var streak = 1
159→        var currentDate = mostRecent
160→
161→        for date in sortedDates.dropFirst() {
162→            let expectedPrevious = calendar.date(byAdding: .day, value: -1, to: currentDate)!
163→            if date == expectedPrevious {
164→                streak += 1
165→                currentDate = date
166→            } else if date == currentDate {
167→                // Same day, skip
168→                continue
169→            } else {
170→                break
171→            }
172→        }
173→
174→        return streak
