21→    func getUserXP() async throws -> UserXP {
22→        let context = context()
23→        var descriptor = FetchDescriptor<SDUserXP>(
24→            predicate: #Predicate { $0.id == "current" }
25→        )
26→        descriptor.fetchLimit = 1
27→
28→        guard let model = try context.fetch(descriptor).first else {
29→            return .empty
30→        }
31→        return model.toDomain()
32→    }
33→
34→    func awardXP(transaction: XPTransaction) async throws -> UserXP {
35→        let context = context()
36→        var descriptor = FetchDescriptor<SDUserXP>(
37→            predicate: #Predicate { $0.id == "current" }
38→        )
39→        descriptor.fetchLimit = 1
40→
41→        let model: SDUserXP
42→        if let existing = try context.fetch(descriptor).first {
43→            model = existing
44→        } else {
45→            model = SDUserXP()
46→            context.insert(model)
47→        }
48→
49→        model.totalXP += transaction.amount
50→        model.lastAwardDate = transaction.date
51→        try context.save()
52→
53→        return model.toDomain()
54→    }
