320→    func listEntries() async throws -> [WorkoutHistoryEntry] {
321→        entries.sorted { $0.date > $1.date }
322→    }
323→    
324→    func listEntries(limit: Int, offset: Int) async throws -> [WorkoutHistoryEntry] {
325→        let sorted = entries.sorted { $0.date > $1.date }
326→        let start = min(offset, sorted.count)
327→        let end = min(offset + limit, sorted.count)
328→        return Array(sorted[start..<end])
329→    }
330→    
331→    func count() async throws -> Int {
332→        entries.count
333→    }
334→
335→    func saveEntry(_ entry: WorkoutHistoryEntry) async throws {
336→        entries.append(entry)
337→    }
338→
339→    func listAppEntriesWithPlan(limit: Int) async throws -> [WorkoutHistoryEntry] {
340→        let filtered = entries
341→            .filter { $0.source == .app && $0.workoutPlan != nil }
342→            .sorted { $0.date > $1.date }
343→        return Array(filtered.prefix(limit))
344→    }
